//SB, DLT, 10/04/2026
/// <summary>
/// Method calls the SalesAgreementLineEntity helper class for the ds - AgreementLine
/// </summary>
public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret;

    ret = next insertEntityDataSource(_entityCtx, _dataSourceCtx);

    if (ret && _dataSourceCtx.name() == dataEntityDataSourceStr(SalesAgreementLineEntity, AgreementLine) && ETGCanadaParameters::find().EnableIntercompanyB2BSync)
    {
        SalesAgreementLineEntity  SalesAgreementLineEntity  = _entityCtx.getEntityRecord();
        AgreementLine     agreementLine_ds     = _dataSourceCtx.getBuffer();

        if(agreementLine_ds is AgreementLineQuantityCommitment)
        {
            AgreementLineQuantityCommitment     agreementLineQuantityCommitment = agreementLine_ds as AgreementLineQuantityCommitment;
            ETGPurchSalesAgreementLineHelper helper = ETGPurchSalesAgreementLineHelper::construct(agreementLineQuantityCommitment);
            helper.run();
        }
    }
    return ret;
}
